(389, 'HP 67 Black Ink Cartridge', 'HP 67 Black Ink Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'hp 67 black ink cartridge', 'hp 67 black ink cartridge hp 67 black ink cartridge hộp mực hp chính hãng được thiết kế để in ấn hàng ngày đáng tin cậy. có mực đen dựa trên bột màu, chất lượng văn bản sắc nét, khả năng tương thích với máy in hp deskjet và envy, khả năng năng suất tiêu chuẩn, đầu ra chống nhòe và thiết kế lắp đặt dễ dàng.'),
(390, 'HP 67 Tri-Color Ink Cartridge', 'HP 67 Tri-Color Ink Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'hp 67 tri-color ink cartridge', 'hp 67 tri-color ink cartridge hp 67 tri-color ink cartridge hộp mực ba màu chính hãng của hp được thiết kế để in màu rực rỡ. có mực lục lam, đỏ tươi và vàng, đầu ra chất lượng ảnh, khả năng tương thích với dòng máy in hp deskjet và envy và hiệu suất năng suất trang đáng tin cậy.'),
(391, 'HP 680 Black Ink Cartridge', 'HP 680 Black Ink Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'hp 680 black ink cartridge', 'hp 680 black ink cartridge hp 680 black ink cartridge hộp mực hp được sử dụng rộng rãi được thiết kế để in tại nhà và văn phòng. có mực đen chống phai màu, chất lượng in ổn định, khả năng tương thích với máy in hp ink advantage và hiệu suất được tối ưu hóa để in tài liệu.'),
