(425, 'Ricoh SP C250 Cyan Toner Cartridge', 'Ricoh SP C250 Cyan Toner Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'ricoh sp c250 cyan toner cartridge', 'ricoh sp c250 cyan toner cartridge ricoh sp c250 cyan toner cartridge hộp mực lục lam ricoh chính hãng được thiết kế để in màu văn phòng sống động. có tính nhất quán mực ổn định và chất lượng hình ảnh chuyên nghiệp.'),
(426, 'Ricoh SP C250 Magenta Toner Cartridge', 'Ricoh SP C250 Magenta Toner Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'ricoh sp c250 magenta toner cartridge', 'ricoh sp c250 magenta toner cartridge ricoh sp c250 magenta toner cartridge hộp mực màu đỏ tươi của ricoh có hiệu suất in laser đáng tin cậy, đầu ra đồ họa sống động và phân phối mực mượt mà.'),
(427, 'Ricoh SP C250 Yellow Toner Cartridge', 'Ricoh SP C250 Yellow Toner Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'ricoh sp c250 yellow toner cartridge', 'ricoh sp c250 yellow toner cartridge ricoh sp c250 yellow toner cartridge hộp mực màu vàng ricoh chất lượng cao được thiết kế để in văn phòng chuyên nghiệp và đồ họa tài liệu sống động.'),
(428, 'Ricoh MP C3503 Black Toner Cartridge', 'Ricoh MP C3503 Black Toner Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'ricoh mp c3503 black toner cartridge', 'ricoh mp c3503 black toner cartridge ricoh mp c3503 black toner cartridge hộp mực ricoh chuyên nghiệp được thiết kế cho máy in văn phòng đa chức năng. có năng suất trang cao, chất lượng văn bản sắc nét và hiệu suất in cấp doanh nghiệp.'),
(429, 'Ricoh MP C3503 Cyan Toner Cartridge', 'Ricoh MP C3503 Cyan Toner Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'ricoh mp c3503 cyan toner cartridge', 'ricoh mp c3503 cyan toner cartridge ricoh mp c3503 cyan toner cartridge mực lục lam chính hãng của ricoh được thiết kế cho đồ họa doanh nghiệp sống động và đầu ra in laser độ phân giải cao.'),
(430, 'Ricoh MP C3503 Magenta Toner Cartridge', 'Ricoh MP C3503 Magenta Toner Cartridge.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'muc', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 05:00:00', '2024-05-14 05:00:00', 'ricoh mp c3503 magenta toner cartridge', 'ricoh mp c3503 magenta toner cartridge ricoh mp c3503 magenta toner cartridge hộp mực màu đỏ tươi chính hãng của ricoh có chất lượng in ổn định và hiệu suất tài liệu màu chuyên nghiệp.');
