INSERT INTO `product_translations` (`id`, `product_id`, `lang`, `title`, `description`, `content`, `created_at`, `updated_at`) VALUES
(389, 389, 'vi', 'HP 67 Black Ink Cartridge', '', '<p>hp 67 black ink cartridge Hộp mực HP chính hãng được thiết kế để in ấn hàng ngày đáng tin cậy. Có mực đen dựa trên bột màu, chất lượng văn bản sắc nét, khả năng tương thích với máy in HP DeskJet và ENVY, khả năng năng suất tiêu chuẩn, đầu ra chống nhòe và thiết kế lắp đặt dễ dàng.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(390, 390, 'vi', 'HP 67 Tri-Color Ink Cartridge', '', '<p>hp 67 tri-color ink cartridge Hộp mực ba màu chính hãng của HP được thiết kế để in màu rực rỡ. Có mực lục lam, đỏ tươi và vàng, đầu ra chất lượng ảnh, khả năng tương thích với dòng máy in HP DeskJet và ENVY và hiệu suất năng suất trang đáng tin cậy.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(391, 391, 'vi', 'HP 680 Black Ink Cartridge', '', '<p>hp 680 black ink cartridge Hộp mực HP được sử dụng rộng rãi được thiết kế để in tại nhà và văn phòng. Có mực đen chống phai màu, chất lượng in ổn định, khả năng tương thích với máy in HP Ink Advantage và hiệu suất được tối ưu hóa để in tài liệu.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(392, 392, 'vi', 'HP 680 Color Ink Cartridge', '', '<p>hp 680 color ink cartridge Hộp mực màu HP chính hãng được thiết kế để in hình ảnh và tài liệu sống động. Có hệ thống mực ba màu tích hợp, dòng mực đáng tin cậy, khả năng tương thích với máy in HP Ink Advantage và khả năng in ảnh chất lượng cao.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(393, 393, 'vi', 'HP 954 Black Ink Cartridge', '', '<p>hp 954 black ink cartridge Hộp mực HP OfficeJet cấp chuyên nghiệp được thiết kế để in ấn cho doanh nghiệp. Có mực bột màu đen năng suất cao, tài liệu chống nước, khả năng tương thích với máy in HP OfficeJet Pro và đầu ra chất lượng doanh nghiệp.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(394, 394, 'vi', 'HP GT53 Black Ink Bottle', '', '<p>hp gt53 black ink bottle Lọ mực HP Smart Tank có thể nạp lại được thiết kế để in với chi phí cực thấp. Có năng suất trang cao, hệ thống nạp lại không tràn, công thức mực đen đậm và khả năng tương thích với máy in HP Smart Tank.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(395, 395, 'vi', 'HP GT52 Color Ink Bottle', '', '<p>hp gt52 color ink bottle Lọ mực màu HP dung lượng cao được thiết kế cho máy in Smart Tank. Có các tùy chọn mực lục lam, đỏ tươi và vàng, khả năng in năng suất cao, tái tạo màu sắc sống động và công nghệ nạp lại dễ dàng.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(396, 396, 'vi', 'Epson 003 Black Ink Bottle', '', '<p>epson 003 black ink bottle Lọ mực Epson EcoTank phổ biến được thiết kế để in số lượng lớn. Có mực đen sắc tố, năng suất trang cực cao, vòi nạp không tràn và khả năng tương thích với máy in Epson EcoTank.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(397, 397, 'vi', 'Epson 003 Cyan Ink Bottle', '', '<p>epson 003 cyan ink bottle Lọ mực lục lam Epson chính hãng được thiết kế cho máy in EcoTank. Có đầu ra màu sắc sống động, năng suất trang cao, hiệu suất chống phai màu và thiết kế nạp lại chính xác để in chi phí thấp.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(398, 398, 'vi', 'Epson 003 Magenta Ink Bottle', '', '<p>epson 003 magenta ink bottle Lọ mực Epson màu đỏ tươi dung lượng cao có hiệu suất màu sắc sống động, khả năng tương thích EcoTank, công nghệ nạp lại chống tràn và chất lượng in lâu dài cho ảnh và tài liệu.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(399, 399, 'vi', 'Epson 003 Yellow Ink Bottle', '', '<p>epson 003 yellow ink bottle Lọ mực màu vàng Epson EcoTank được thiết kế để in hình ảnh và đồ họa sống động. Có sản lượng năng suất cao, công thức mực chống phai màu và hoạt động nạp lại đáng tin cậy.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(400, 400, 'vi', 'Epson 664 Black Ink Bottle', '', '<p>epson 664 black ink bottle Lọ mực nạp lại Epson được mua rộng rãi được thiết kế cho máy in EcoTank. Tính năng in chi phí cực thấp, năng suất trang cao, mực đen sắc tố và hiệu suất tối ưu hóa để in tài liệu.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(401, 401, 'vi', 'Epson 664 Cyan Ink Bottle', '', '<p>epson 664 cyan ink bottle Chai nạp lục lam Epson chính hãng có năng suất trang cao, đầu ra màu sắc sống động, khả năng tương thích EcoTank và hiệu suất in đáng tin cậy cho mục đích kinh doanh và gia đình.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(402, 402, 'vi', 'Epson T673 Photo Black Ink Bottle', '', '<p>epson t673 photo black ink bottle Mực đen ảnh Epson cao cấp được thiết kế cho máy in ảnh và đầu ra hình ảnh chuyên nghiệp. Có tông màu đen sâu, chất lượng in độ phân giải cao và khả năng tương thích với máy in ảnh Epson L-series.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(403, 403, 'vi', 'OKI C332 Black Toner Cartridge', '', '<p>oki c332 black toner cartridge Hộp mực chính hãng OKI được thiết kế để in đơn sắc đáng tin cậy. Có công nghệ in laser, đầu ra văn bản sắc nét, khả năng tương thích với máy in dòng OKI C332 và hiệu suất mực ổn định.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(404, 404, 'vi', 'OKI C332 Cyan Toner Cartridge', '', '<p>oki c332 cyan toner cartridge Hộp mực màu lục lam chính hãng OKI được thiết kế để in laser màu sắc sống động. Có đầu ra màu độ phân giải cao, dòng mực đáng tin cậy và khả năng tương thích với máy in laser màu OKI.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(405, 405, 'vi', 'OKI C332 Magenta Toner Cartridge', '', '<p>oki c332 magenta toner cartridge Hộp mực màu đỏ tươi OKI chất lượng cao được thiết kế để in màu chuyên nghiệp. Có chất lượng in nhất quán, đầu ra chính xác bằng laser và hiệu suất năng suất trang ổn định.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(406, 406, 'vi', 'OKI C332 Yellow Toner Cartridge', '', '<p>oki c332 yellow toner cartridge Hộp mực màu vàng chính hãng của OKI có khả năng tái tạo màu sắc rực rỡ, phân phối mực mượt mà và khả năng tương thích với máy in dòng OKI C332.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(407, 407, 'vi', 'OKI B412 Black Toner Cartridge', '', '<p>oki b412 black toner cartridge Hộp mực đơn sắc đáng tin cậy được thiết kế cho máy in doanh nghiệp OKI. Có đầu ra tài liệu sắc nét, năng suất trang cao, tính nhất quán in bền và khả năng in văn phòng hiệu quả.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(408, 408, 'vi', 'OKI MC363 Black Toner Cartridge', '', '<p>oki mc363 black toner cartridge Hộp mực OKI chuyên nghiệp được thiết kế cho máy in laser đa chức năng. Có chất lượng in đen phong phú, hiệu suất mực ổn định và đầu ra in doanh nghiệp đáng tin cậy.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(409, 409, 'vi', 'OKI MC363 Cyan Toner Cartridge', '', '<p>oki mc363 cyan toner cartridge Mực lục lam OKI chính hãng được thiết kế cho máy in văn phòng đa chức năng. Có chất lượng màu sắc sống động, sử dụng mực hiệu quả và hiệu suất in laser độ phân giải cao.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(410, 410, 'vi', 'Canon GI-790 Black Ink Bottle', '', '<p>canon gi-790 black ink bottle Lọ mực nạp chính hãng của Canon được thiết kế cho máy in PIXMA G-series. Có năng suất trang cao, mực đen sắc tố, hệ thống nạp lại chống tràn và hiệu suất in tài liệu chi phí thấp.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(411, 411, 'vi', 'Canon GI-790 Cyan Ink Bottle', '', '<p>canon gi-790 cyan ink bottle Chai nạp lục lam chính hãng của Canon có đầu ra màu sắc sống động, dòng mực mượt mà, khả năng tương thích với máy in PIXMA G-series và chất lượng in ảnh đáng tin cậy.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(412, 412, 'vi', 'Canon GI-790 Magenta Ink Bottle', '', '<p>canon gi-790 magenta ink bottle Lọ mực màu đỏ tươi dung lượng cao của Canon được thiết kế để in hình ảnh sống động và đồ họa văn phòng. Có hiệu suất nạp lại ổn định và độ chính xác màu tuyệt vời.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(413, 413, 'vi', 'Canon GI-790 Yellow Ink Bottle', '', '<p>canon gi-790 yellow ink bottle Chai nạp lại màu vàng của Canon được thiết kế để có đồ họa sống động và in ảnh. Có hiệu suất màu chống phai màu và khả năng in năng suất cao.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(414, 414, 'vi', 'Canon PG-745 Black Ink Cartridge', '', '<p>canon pg-745 black ink cartridge Hộp mực đen phổ biến của Canon được thiết kế cho máy in PIXMA. Có mực đen sắc tố, in tài liệu sắc nét, phân phối mực đáng tin cậy và lắp đặt hộp mực dễ dàng.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(415, 415, 'vi', 'Canon CL-746 Color Ink Cartridge', '', '<p>canon cl-746 color ink cartridge Hộp mực màu chính hãng của Canon được thiết kế để in ảnh và tài liệu sống động. Có hệ thống mực ba màu, chất lượng hình ảnh sống động và khả năng tương thích với máy in PIXMA.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(416, 416, 'vi', 'Canon Cartridge 325 Toner', '', '<p>canon cartridge 325 toner Hộp mực laser Canon được sử dụng rộng rãi được thiết kế để in văn phòng đơn sắc. Có đầu ra văn bản sắc nét, năng suất trang đáng tin cậy và khả năng tương thích với máy in Canon imageCLASS.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(417, 417, 'vi', 'Brother BT-D60 Black Ink Bottle', '', '<p>brother bt-d60 black ink bottle Lọ mực nạp lại Brother chính hãng được thiết kế cho máy in InkBenefit Tank. Có năng suất trang cực cao, mực đen sắc tố và hiệu suất in văn phòng chi phí thấp đáng tin cậy.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(418, 418, 'vi', 'Brother BT5000 Cyan Ink Bottle', '', '<p>brother bt5000 cyan ink bottle Chai nạp lục lam Brother chính hãng được thiết kế để in màu sắc sống động và hiệu suất dòng mực mượt mà. Tương thích với máy in bình mực Brother.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(419, 419, 'vi', 'Brother BT5000 Magenta Ink Bottle', '', '<p>brother bt5000 magenta ink bottle Lọ mực Brother màu đỏ tươi dung lượng cao được thiết kế để in đồ họa và hình ảnh sống động. Có thiết kế nạp lại đáng tin cậy và chất lượng in nhất quán.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(420, 420, 'vi', 'Brother BT5000 Yellow Ink Bottle', '', '<p>brother bt5000 yellow ink bottle Chai nạp lại màu vàng Brother được thiết kế để in tài liệu và hình ảnh đầy màu sắc. Có năng suất trang cao và hiệu suất tối ưu cho máy in Brother.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(421, 421, 'vi', 'Brother TN-2385 Black Toner Cartridge', '', '<p>brother tn-2385 black toner cartridge Hộp mực đơn sắc Brother phổ biến được thiết kế cho máy in văn phòng laser. Có văn bản màu đen sắc nét, năng suất trang đáng tin cậy và hiệu suất in văn phòng nhất quán.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(422, 422, 'vi', 'Brother TN-261 Cyan Toner Cartridge', '', '<p>brother tn-261 cyan toner cartridge Hộp mực lục lam Brother chính hãng được thiết kế để in laser màu chuyên nghiệp. Có chất lượng màu sắc sống động và khả năng tương thích với máy in laser Brother.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(423, 423, 'vi', 'Brother TN-261 Magenta Toner Cartridge', '', '<p>brother tn-261 magenta toner cartridge Mực Brother màu đỏ tươi chuyên nghiệp có đầu ra màu sắc rực rỡ, dòng mực mượt mà và hiệu suất in laser chất lượng cao.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(424, 424, 'vi', 'Ricoh SP C250 Black Toner Cartridge', '', '<p>ricoh sp c250 black toner cartridge Hộp mực đơn sắc Ricoh chính hãng được thiết kế để in laser văn phòng. Có đầu ra tài liệu sắc nét, hiệu suất mực đáng tin cậy và khả năng tương thích với máy in dòng Ricoh SP.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(425, 425, 'vi', 'Ricoh SP C250 Cyan Toner Cartridge', '', '<p>ricoh sp c250 cyan toner cartridge Hộp mực lục lam Ricoh chính hãng được thiết kế để in màu văn phòng sống động. Có tính nhất quán mực ổn định và chất lượng hình ảnh chuyên nghiệp.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(426, 426, 'vi', 'Ricoh SP C250 Magenta Toner Cartridge', '', '<p>ricoh sp c250 magenta toner cartridge Hộp mực màu đỏ tươi của Ricoh có hiệu suất in laser đáng tin cậy, đầu ra đồ họa sống động và phân phối mực mượt mà.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(427, 427, 'vi', 'Ricoh SP C250 Yellow Toner Cartridge', '', '<p>ricoh sp c250 yellow toner cartridge Hộp mực màu vàng Ricoh chất lượng cao được thiết kế để in văn phòng chuyên nghiệp và đồ họa tài liệu sống động.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(428, 428, 'vi', 'Ricoh MP C3503 Black Toner Cartridge', '', '<p>ricoh mp c3503 black toner cartridge Hộp mực Ricoh chuyên nghiệp được thiết kế cho máy in văn phòng đa chức năng. Có năng suất trang cao, chất lượng văn bản sắc nét và hiệu suất in cấp doanh nghiệp.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(429, 429, 'vi', 'Ricoh MP C3503 Cyan Toner Cartridge', '', '<p>ricoh mp c3503 cyan toner cartridge Mực lục lam chính hãng của Ricoh được thiết kế cho đồ họa doanh nghiệp sống động và đầu ra in laser độ phân giải cao.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00'),
(430, 430, 'vi', 'Ricoh MP C3503 Magenta Toner Cartridge', '', '<p>ricoh mp c3503 magenta toner cartridge Hộp mực màu đỏ tươi chính hãng của Ricoh có chất lượng in ổn định và hiệu suất tài liệu màu chuyên nghiệp.</p>', '2024-05-14 05:00:00', '2024-05-14 05:00:00');
